// 테스트용 - 현재 달 조회
const now = new Date();
const firstDay = new Date(now.getFullYear(), now.getMonth(), 1);
const lastDay = new Date(now.getFullYear(), now.getMonth() + 1, 0);

const toNZ = (d) => {
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  return `${dd}-${mm}-${yyyy}`;
};

const toISO = (d) => d.toISOString().split('T')[0];

const monthLabel = firstDay.toLocaleString('en-NZ', { year: 'numeric', month: 'long' });

return [{
  json: {
    dateFrom: toISO(firstDay),   // PostgreSQL  "2025-05-01"
    dateTo: toISO(lastDay),      // PostgreSQL  "2025-05-31"
    dateFromNZ: toNZ(firstDay),  // Display "01-05-2025"
    dateToNZ: toNZ(lastDay),     // Display "31-05-2025"
    monthLabel                   // "May 2025"
  }
}];

const hospitalInfo = {
  'H-001': { email: 'chchent@examples.com' },
  'H-002': { email: 'selwynhearing@examples.com' },
  'H-003': { email: 'Canterburyaa@examples.com' }
};

const formatNZD = (amount) => {
  return Number(amount).toLocaleString('en-NZ', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
};
const rows = $input.all();
const monthLabel = $('Date Filter').first().json.monthLabel;

// Grouping with hospital name
const hospitals = {};
for (const row of rows) {
  const d = row.json;
  const key = d.hospital_id;
  if (!hospitals[key]) {
    hospitals[key] = {
      hospital_id: d.hospital_id,
      hospital_name: d.hospital_name,
      rows: []
    };
  }
  hospitals[key].rows.push(d);
}

// Generate per hospital
const results = [];

for (const key of Object.keys(hospitals)) {
  const hospital = hospitals[key];
  const headers = [
    'Date', 'Patient', 'Brand', 'Model', 'Ear Side',
    'Sale Price (NZD)', 'Revenue Share Rate', 'Hospital Share (NZD)'
  ];

  const lines = [headers.join(',')];
  let totalSalePrice = 0;
  let totalHospitalShare = 0;

  for (const d of hospital.rows) {
    const date = new Date(d.record_date).toLocaleDateString('en-NZ', {
      day: '2-digit', month: '2-digit', year: 'numeric'
    }).replace(/\//g, '-');

    totalSalePrice += Number(d.sale_price);
    totalHospitalShare += Number(d.hospital_share);

    lines.push([
      date,
      `"${d.patient_name}"`,
      d.brand || '',
      `"${d.product_model || ''}"`,
      d.ear_side || '',
      d.sale_price,
      d.revenue_share_rate,
      d.hospital_share
    ].join(','));
  }

  lines.push([
    '', '', '', '', 'TOTAL',
    totalSalePrice.toFixed(2),
    '',
    totalHospitalShare.toFixed(2)
  ].join(','));

  const base64 = Buffer.from(lines.join('\n')).toString('base64');

  results.push({
    json: {
      hospital_id: hospital.hospital_id,
      hospital_name: hospital.hospital_name,
      contact_email: hospitalInfo[hospital.hospital_id].email,
      fileName: `Hospital_Settlement_${hospital.hospital_name.replace(/ /g, '_')}_${monthLabel.replace(' ', '_')}.csv`,
      monthLabel,
      totalSalePrice: formatNZD(totalSalePrice),
      totalHospitalShare: formatNZD(totalHospitalShare)
    },
    binary: {
      data: {
        data: Buffer.from(lines.join('\n')).toString('base64'),
        mimeType: 'text/csv',
        fileName: `Hospital_Settlement_${hospital.hospital_name.replace(/ /g, '_')}_${monthLabel.replace(' ', '_')}.csv`
      }
    }
  });
}

return results;

